#!/usr/bin/env bash
# compare-5b-results.sh — fetch + tabulate paris-residual-diff JSON artifacts
# from gs://${PROJECT}_paris5b/ to render cross-build / cross-profile summaries.
#
# Usage:
#   ./compare-5b-results.sh                    # list latest- aliases for all profiles
#   ./compare-5b-results.sh latest             # tabulate the per-profile latest
#   ./compare-5b-results.sh BUILD_ID [BUILD_ID...]  # tabulate by exact build id(s)
#   ./compare-5b-results.sh canonical precise  # tabulate by latest-<model>-<slug>
#
# Reads:   gs://${PROJECT}_paris5b/<key>.json (schema paris-residual-diff/v1)
# Prints:  one summary row per artifact (profile, layers, cliffs, L0 cos, end cos)
# Plus:    per-layer cosine grid for first 5 / interesting layers
#
# Requires: gcloud + gsutil + jq + python3 (with optional numpy for grid).
set -euo pipefail

PROJECT="${PROJECT_ID:-neutral-418500}"
BUCKET="gs://${PROJECT}_paris5b"
MODEL="${MODEL_NAME:-llama-70b}"
TMP="$(mktemp -d)"
trap 'rm -rf "${TMP}"' EXIT

list_latest() {
  echo "── ${BUCKET} latest- aliases ──"
  gsutil ls "${BUCKET}/latest-*.json" 2>/dev/null \
    | sed -E "s|${BUCKET}/||" | sort
}

resolve_key() {
  # Resolve a CLI arg to a GCS object name:
  #   - "latest"               → latest-<model>-*.json (all profiles)
  #   - "<profile>"            → latest-<model>-<profile>.json (single profile)
  #   - "<build-id>"           → <build-id>-<model>-*.json (all profiles in that build)
  local arg="$1"
  if [[ "${arg}" == "latest" ]]; then
    gsutil ls "${BUCKET}/latest-${MODEL}-*.json" 2>/dev/null
    return
  fi
  # Heuristic: build IDs are UUID-shaped (8-4-4-4-12 hex), profile slugs aren't.
  if [[ "${arg}" =~ ^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$ ]]; then
    gsutil ls "${BUCKET}/${arg}-${MODEL}-*.json" 2>/dev/null
    return
  fi
  # Otherwise treat as profile slug.
  gsutil ls "${BUCKET}/latest-${MODEL}-${arg}.json" 2>/dev/null
}

if [[ $# -eq 0 ]]; then
  list_latest
  exit 0
fi

KEYS=()
for arg in "$@"; do
  while IFS= read -r line; do
    [[ -n "${line}" ]] && KEYS+=("${line}")
  done < <(resolve_key "${arg}")
done

if [[ ${#KEYS[@]} -eq 0 ]]; then
  echo "compare-5b-results.sh: no matching keys for: $*" >&2
  exit 1
fi

# Fetch all artifacts.
LOCAL=()
for key in "${KEYS[@]}"; do
  fname="$(basename "${key}")"
  gsutil -q cp "${key}" "${TMP}/${fname}"
  LOCAL+=("${TMP}/${fname}")
done

# Summary table.
echo
echo "── 5b summary (${#LOCAL[@]} artifacts) ──"
printf '%-50s  %-6s  %-7s  %-15s  %-12s  %-12s\n' \
  "key" "layers" "cliffs" "cliff_layers" "L0 cos" "end ‖d-r‖∞"
for art in "${LOCAL[@]}"; do
  fname="$(basename "${art}")"
  python3 - "${art}" "${fname}" <<'PYEOF'
import json, sys
art_path = sys.argv[1]
fname = sys.argv[2]
with open(art_path) as f:
    a = json.load(f)
cliffs = a.get('cliffs', [])
cliff_layers = ','.join(str(c['layer']) for c in cliffs) or '-'
l0 = a.get('l0') or {}
end = a.get('end') or {}
print(f"{fname:<50}  {a.get('num_layers', '?'):<6}  {len(cliffs):<7}  "
      f"{cliff_layers:<15}  {l0.get('cos', float('nan')):<12.6f}  "
      f"{end.get('linf', float('nan')):<12.4e}")
PYEOF
done

# Cross-build per-layer cos diff (only if exactly 2 artifacts).
if [[ ${#LOCAL[@]} -eq 2 ]]; then
  echo
  echo "── per-layer cos diff (A=${LOCAL[0]##*/}  B=${LOCAL[1]##*/}) ──"
  python3 - "${LOCAL[0]}" "${LOCAL[1]}" <<'PYEOF'
import json, sys
A = json.load(open(sys.argv[1]))
B = json.load(open(sys.argv[2]))
ra = {r['layer']: r for r in A['rows']}
rb = {r['layer']: r for r in B['rows']}
common = sorted(set(ra) & set(rb))
print(f"{'L':>3}  {'A cos':>10}  {'B cos':>10}  {'cos B-A':>10}  "
      f"{'A linf':>12}  {'B linf':>12}")
# First 20 layers in detail; then every 5th past L20.
selected = [i for i in common if i < 20 or i % 5 == 0]
for i in selected:
    a, b = ra[i], rb[i]
    print(f"{i:>3}  {a['cos']:>10.6f}  {b['cos']:>10.6f}  "
          f"{(b['cos']-a['cos']):>+10.6f}  "
          f"{a['linf']:>12.4e}  {b['linf']:>12.4e}")
PYEOF
fi
